#include <iostream>
#include <unordered_map>
#include <ctime>
using namespace std;

struct Session {
    string data; // assuming session data is a string, you can replace it with your own struct/class if needed
    time_t expiryTime; 
};

class SessionCache {
private:
    unordered_map<string, Session*> cache;
public:
    ~SessionCache() {
        for(auto& kv : cache) delete kv.second;
    }

    void createSession(const string& sessionId, const string& data, int ttl = 3600) {
        time_t expiry = time(NULL) + ttl; // current time plus TTL in seconds
        Session* sess = new Session{data, expiry}; 
        cache[sessionId] = sess;
    }

    string accessSession(const string& sessionId) {
        auto it = cache.find(sessionId);
        if (it == cache.end() || it->second->expiryTime < time(NULL)) { 
            // Session not found or expired
            return "";
        } else {
            // Extend session TTL on access
            it->second->expiryTime = time(NULL) + 3600;  
            return it->second->data;
        }
    }

    void invalidateSession(const string& sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            delete it->second;  // Free memory
            cache.erase(it);   // Remove from map
        }
    }
};